UpdateSourceArgs:
-c "cfg='{{$FullBaseDir}}RSDragonwilds/Saved/Config/Linux/DedicatedServer.ini'; touch "$cfg"; tmp=$(mktemp); grep -Ev '^(OwnerId|ServerName|DefaultWorldName|AdminPassword|WorldPassword)=' "$cfg" > "$tmp" || true; mv "$tmp" "$cfg"; printf 'OwnerId={{OwnerId}}
ServerName={{ServerName}}
DefaultWorldName={{DefaultWorldName}}
AdminPassword={{AdminPassword}}
' >> "$cfg"; if [ -n "{{WorldPassword}}" ]; then printf 'WorldPassword={{WorldPassword}}
' >> "$cfg"; fi"
